type MsgServer interface {
	// RegisterTool registers a new tool
	RegisterTool(context.Context, *MsgRegisterTool) (*MsgRegisterToolResponse, error)
	// UpdateTool updates an existing tool
	UpdateTool(context.Context, *MsgUpdateTool) (*MsgUpdateToolResponse, error)
	// DelistTool removes a tool from the registry
	DelistTool(context.Context, *MsgDelistTool) (*MsgDelistToolResponse, error)
	// SubmitReceipt submits a usage receipt
	SubmitReceipt(context.Context, *MsgSubmitReceipt) (*MsgSubmitReceiptResponse, error)
	// AnchorBundle anchors a receipt bundle merkle root on-chain for trustless
	// verification.
	AnchorBundle(context.Context, *MsgAnchorBundle) (*MsgAnchorBundleResponse, error)
	// ChallengeReceipt challenges a receipt
	ChallengeReceipt(context.Context, *MsgChallengeReceipt) (*MsgChallengeReceiptResponse, error)
	// SettleReceipt settles a receipt after dispute window
	SettleReceipt(context.Context, *MsgSettleReceipt) (*MsgSettleReceiptResponse, error)
	// UpdateParams updates module parameters
	UpdateParams(context.Context, *MsgUpdateParams) (*MsgUpdateParamsResponse, error)
	// SetSLATemplate publishes an SLA template (governance authority only).
	SetSLATemplate(context.Context, *MsgSetSLATemplate) (*MsgSetSLATemplateResponse, error)
	// SetDisputeTerms publishes dispute terms (governance authority only).
	SetDisputeTerms(context.Context, *MsgSetDisputeTerms) (*MsgSetDisputeTermsResponse, error)
	// SetLaneRegistryEntry publishes a lane registry entry (governance authority
	// only).
	SetLaneRegistryEntry(context.Context, *MsgSetLaneRegistryEntry) (*MsgSetLaneRegistryEntryResponse, error)
	// SetToolCapsule registers or updates tool capsule metadata.
	SetToolCapsule(context.Context, *MsgSetToolCapsule) (*MsgSetToolCapsuleResponse, error)
	// CreateBond creates or updates a bond for a tool
	CreateBond(context.Context, *MsgCreateBond) (*MsgCreateBondResponse, error)
	// WithdrawBond withdraws a bond
	WithdrawBond(context.Context, *MsgWithdrawBond) (*MsgWithdrawBondResponse, error)
	// RegisterWatcher registers or tops up a watcher stake
	RegisterWatcher(context.Context, *MsgRegisterWatcher) (*MsgRegisterWatcherResponse, error)
	// UnregisterWatcher withdraws watcher stake and removes from registry
	UnregisterWatcher(context.Context, *MsgUnregisterWatcher) (*MsgUnregisterWatcherResponse, error)
	// SubmitSLOProbeReceipt submits a watcher SLO probe receipt
	SubmitSLOProbeReceipt(context.Context, *MsgSubmitSLOProbeReceipt) (*MsgSubmitSLOProbeReceiptResponse, error)
	// SetOriginRoutingConfig creates or updates an origin routing config
	// (governance authority only).
	SetOriginRoutingConfig(context.Context, *MsgSetOriginRoutingConfig) (*MsgSetOriginRoutingConfigResponse, error)
}

